import React from 'react';
import { makeStyles } from '@material-ui/core/styles';
import AppBar from '@material-ui/core/AppBar';
import Tabs from '@material-ui/core/Tabs';
import Tab from '@material-ui/core/Tab';

function a11yProps(index) {
    return {
        id: `scrollable-auto-tab-${index}`,
        'aria-controls': `scrollable-auto-tabpanel-${index}`,
    };
}

const useStyles = makeStyles((theme) => ({
    root: {
        flexGrow: 1,
        width: '100%',
        marginTop: 10,
        backgroundColor: theme.palette.background.paper,
    },
}));

function TabPanel(props) {
    const { children, value, index, ...other } = props;
    return (
        <div
            role="tabpanel"
            hidden={value !== index}
            id={`scrollable-force-tabpanel-${index}`}
            aria-labelledby={`scrollable-force-tab-${index}`}
            {...other}
        >
            {value === index && (
                <div style={{marginTop: 20}}>{children}</div>
            )}
        </div>
    );
}

export default function Index() {
    const classes = useStyles()
    const [value, setValue] = React.useState(0)

    const handleChange = (event, newValue) => {
        setValue(newValue)
    }

    return (
        <div className={classes.root} style={{ backgroundColor: 'whitesmoke', height: '80vh' }}>
            <AppBar position="static" color="default" style={{ backgroundColor: 'white' }}>
                <Tabs
                    value={value}
                    onChange={handleChange}
                    indicatorColor="primary"
                    variant="scrollable"
                    scrollButtons="auto"
                    aria-label="scrollable auto tabs example"
                >
                    <Tab label="Package Information" {...a11yProps(0)} style={{ textTransform: 'none' }} />
                    <Tab label="Delete Package" {...a11yProps(1)} style={{ textTransform: 'none' }} />
                    <Tab label="Buy Package" {...a11yProps(2)} style={{ textTransform: 'none' }} />
                    <Tab label="Buy IR Package" {...a11yProps(3)} style={{ textTransform: 'none' }} />
                </Tabs>
            </AppBar>

            <TabPanel value={value} index={0}>
                1
            </TabPanel>
            <TabPanel value={value} index={1}>
                2
            </TabPanel>
            <TabPanel value={value} index={2}>
                3
            </TabPanel>
            <TabPanel value={value} index={3}>
                4
            </TabPanel>


        </div>
    )
}
